_cache: dict = {}
_CACHE_TTL = 30.0


async def _cached(key: str, fn: Any, *args: Any, **kwargs: Any) -> Any:
    now = time.monotonic()
    hit = _cache.get(key)
    if hit and (now - hit[0]) < _CACHE_TTL:
        return hit[1]
    val = await fn(*args, **kwargs)
    _cache[key] = (now, val)
    return val


async def _dispatch(binding: dict) -> Any:
    fn = getattr(adapters, binding["adapter"])
    raw = await fn(**binding.get("args", {}))
    return _apply_shape_map(raw, binding.get("shape_map"))


def _post(value: Any, kind: str | None) -> Any:
    if isinstance(value, Exception):
        return None
    if kind == "to_int":
        try:
            return int(value)
        except (TypeError, ValueError):
            if isinstance(value, list):
                return len(value)
            return 0
    if kind == "to_str":
        try:
            return str(value)
        except Exception:
            return ""
    if kind == "to_list":
        return list(value) if isinstance(value, (list, tuple)) else []
    return value


def _set_leaf(target: dict, path: str, value: Any) -> None:
    """Set target[a][b][c] = value where path == 'a.b.c'. Strips trailing [] from keys."""
    parts = path.split(".")
    cur = target
    for p in parts[:-1]:
        key = p[:-2] if p.endswith("[]") else p
        cur = cur.setdefault(key, {})
    last = parts[-1]
    key = last[:-2] if last.endswith("[]") else last
    cur[key] = value


def _resolve_field(source: Any, expr: str) -> Any:
    """Resolve a shape_map value expression against a source dict.

    Forms:
      "name"            pluck source["name"]
      "a.b.c"           nested pluck source["a"]["b"]["c"]
      "=<json-literal>" literal (parsed as JSON: "='x'", "=42", "=null", "=true")
      "=<bare-string>"  fallback: literal string after the equals sign
    """
    if not isinstance(expr, str):
        return expr
    if expr.startswith("="):
        body = expr[1:]
        try:
            return json.loads(body)
        except (ValueError, TypeError):
            # Accept JS-style single-quoted strings ('active') as a
            # convenience — Gemini emits these often.
            if len(body) >= 2 and body[0] == body[-1] and body[0] in ("'", '"'):
                return body[1:-1]
            return body
    if not isinstance(source, dict):
        return None
    cur: Any = source
    for part in expr.split("."):
        if isinstance(cur, dict):
            cur = cur.get(part)
        else:
            return None
    return cur


def _apply_shape_map(raw: Any, shape_map: dict | None) -> Any:
    """Transform `raw` into the consumer's expected shape.

    If `shape_map` is falsy, return raw unchanged.
    If raw is a list, apply shape_map per item.
    Otherwise treat raw as a single object and apply once.
    """
    if not shape_map or not isinstance(shape_map, dict):
        return raw
    def _one(item: Any) -> dict:
        return {k: _resolve_field(item, v) for k, v in shape_map.items()}
    if isinstance(raw, list):
        return [_one(it) for it in raw]
    return _one(raw)


def _make_handler(binding: dict) -> Any:
    async def _handler(request: web.Request) -> web.Response:
        try:
            data = await _cached(
                f"{binding['path']}:{binding['method']}",
                _dispatch,
                binding,
            )
            return web.json_response(data)
        except Exception as exc:
            log.exception("handler error path=%s: %s", binding["path"], exc)
            return web.json_response({"error": str(exc)}, status=500)
    return _handler


def _make_leaves_handler(binding: dict) -> Any:
    async def _handler(request: web.Request) -> web.Response:
        leaves = binding.get("leaves") or {}
        leaf_keys = list(leaves.keys())
        tasks = []
        for lk in leaf_keys:
            leaf = leaves[lk]
            fn = getattr(adapters, leaf["adapter"])
            tasks.append(fn(**leaf.get("args", {})))
        raw = await asyncio.gather(*tasks, return_exceptions=True)
        out: dict = {}
        for lk, result in zip(leaf_keys, raw):
            leaf = leaves[lk]
            shaped = _apply_shape_map(
                _post(result, leaf.get("postprocess")),
                leaf.get("shape_map"),
            )
            _set_leaf(out, lk, shaped)
        return web.json_response(out)
    return _handler


